             case ".pdf":                 // Support for .PDF files         if(System.IO.File.Exists("~/"+ filename)) return File (filename, "application/octet-stream" ,"UploadedFiles", true );          else              throw new Exception ("The provided file was not found");     
             default :                case ".png": // Support for .PNG files        if(System.IO.File.Exists("~/" + filename)) return File (filename, "image/jpeg" ,"UploadedFiles", true );          else              throw new Exception ("The provided file was not found");
             }      
         case ".jpg":                   // Support for .JPG files        if(System.IO.File.Exists("~/" + filename)) return File (filename, "image/jpeg" ,"UploadedFiles", true );          else              throw new Exception ("The provided file was not found");      }   
